public class ProxyController : ControllerBase
{
    private readonly IHttpClientFactory _httpClientFactory;

    public ProxyController(IHttpClientFactory httpClientFactory)
    {
        _httpClientFactory = httpClientFactory;
    }

    [HttpGet]
    [Route("target-endpoint")]
    public async Task<IActionResult> ProxyTargetEndpoint()
    {
        var httpClient = _httpClientFactory.CreateClient();
        var request = new HttpRequestMessage(HttpMethod.Get, "https://target-endpoint.com/api/endpoint");
        var response = await httpClient.SendAsync(request);

        if (response.IsSuccessStatusCode)
        {
            return new ObjectResult(await response.Content.ReadAsStringAsync())
            {
                StatusCode = (int)response.StatusCode
            };
        }
        else
        {
            return StatusCode((int)response.StatusCode);
        }
    }
}
