Here's an example of how you can store the token in a MongoDB collection associated with a user and keep checking for its validity.

**User Model**
```python
from pymongo import MongoClient
from datetime import datetime, timedelta

class User:
    def __init__(self, collection):
        self.collection = collection

    def store_token(self, user_id, token, expires_at):
        """Store the token in the collection."""
        token_doc = {
            'user_id': user_id,
            'token': token,
            'expires_at': expires_at
        }
        self.collection.insert_one(token_doc)

    def get_token(self, user_id):
        """Get the token associated with the user."""
        return self.collection.find_one({'user_id': user_id})

    def revalidate_token(self, user_id, token):
        """Revalidate the token by checking if it exists and is valid."""
        token_doc = self.get_token(user_id)
        if token_doc:
            if datetime.now() < token_doc['expires_at']:
                return token_doc['token'] == token
        return False

    def delete_token(self, user_id):
        """Delete the token associated with the user."""
        self.collection.delete_one({'user_id': user_id})
```

